#include <stdio.h>
#include <math.h>

long long maxPoints(long long N, long long A, long long B) {
    long long e = 0; // exponent of 2
    while ((N & 1LL) == 0) { // N even
        N >>= 1;
        e++;
    }
    long long oddPrimeCount = 0;
    for (long long p = 3; p * p <= N; p += 2) {
        while (N % p == 0) {
            N /= p;
            oddPrimeCount++;
        }
    }
    if (N > 1) oddPrimeCount++; // remaining odd prime

    long long a, b;
    if (e == 0) a = 0; else a = (A >= 0) ? e : 1;
    if (oddPrimeCount == 0) b = 0; else b = (B >= 0) ? oddPrimeCount : 1;
    return a * A + b * B;
}

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, A, B;
        scanf("%lld %lld %lld", &N, &A, &B);
        printf("%lld\n", maxPoints(N, A, B));
    }
    return 0;
}

