#!/usr/bin/env python3
import sys

def max_points(N, A, B):
    e = 0
    while N % 2 == 0:
        N //= 2
        e += 1
    odd_cnt = 0
    p = 3
    while p * p <= N:
        while N % p == 0:
            N //= p
            odd_cnt += 1
        p += 2
    if N > 1:
        odd_cnt += 1
    a = 0 if e == 0 else (e if A >= 0 else 1)
    b = 0 if odd_cnt == 0 else (odd_cnt if B >= 0 else 1)
    return a * A + b * B

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); A = int(next(it)); B = int(next(it))
        out_lines.append(str(max_points(N, A, B)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

